/* DANGEROUS — naive pattern /
int len = sprintf(buf,
"buffer_size: %zu\n"
"bytes_used:  %zu\n"
/ ... more fields ... /
"field_50: %s\n",   / 50 fields */
...);
*eof = 1;
return len;

if internal_buffer is empty:
call show(seq_file, v)   ← fills internal buf
copy min(N, count) bytes → userspace
advance seq_file.from by bytes copied
if all bytes delivered:
set EOF flag
return bytes copied (or 0 for EOF)

c
static int mydevice_proc_show(
struct seq_file *m, void v)
{
seq_printf(m, "buffer_size:  %zu\n",
buffer_size);
seq_printf(m, "bytes_used:   %zu\n",
buffer_data_len);
seq_printf(m, "open_count:   %d\n",
atomic_read(&open_count));
seq_printf(m, "read_count:   %d\n",
atomic_read(&read_count));
seq_printf(m, "write_count:  %d\n",
atomic_read(&write_count));
return 0;  / always */
}

c
static const struct proc_ops mydevice_proc_ops = {
.proc_open    = mydevice_proc_open,
/* provided by seq_file infrastructure: */
.proc_read    = seq_read,
.proc_lseek   = seq_lseek,
.proc_release = single_release,
};
proc_create("mydevice", 0444, NULL,
&mydevice_proc_ops);
